"""
多因子评分策略 (Multi-Factor Scoring)
综合动量、波动率、趋势多个因子打分排序。
"""

def strategy():
    scores = {}

    for ticker in ctx.tickers:
        score = 0

        # 因子1: 动量 (20日)
        mom = ctx.momentum(ticker, 20)
        if not mom.empty:
            mom_score = mom.iloc[-1]
            score = score + mom_score * 2  # 权重2

        # 因子2: 趋势 (在200日均线上方)
        if ctx.price_above_ma(ticker, 200):
            score = score + 10

        # 因子3: 波动率 (低波动加分)
        vol = ctx.volatility(ticker, 20, annualize=True)
        if not vol.empty:
            vol_val = vol.iloc[-1]
            if vol_val < 0.15:
                score = score + 5  # 低波动
            elif vol_val > 0.30:
                score = score - 5  # 高波动

        # 因子4: RSI (避免极端)
        rsi = ctx.rsi(ticker)
        if not rsi.empty:
            rsi_val = rsi.iloc[-1]
            if 40 < rsi_val < 60:
                score = score + 3  # 健康区间

        scores[ticker] = score
        ctx.log(f"📊 {ticker} 综合评分: {score:.1f}")

    # 根据评分分配权重
    total_score = sum(max(s, 0) for s in scores.values())
    weights = {}

    if total_score > 0:
        for ticker, score in scores.items():
            if score > 0:
                weights[ticker] = (score / total_score) * 100
            else:
                weights[ticker] = 0
    else:
        # 全部负分，等权分配避险
        n = len(ctx.tickers)
        weights = {t: 100/n for t in ctx.tickers}
        ctx.log("⚠️ 所有资产评分为负，等权配置")

    ctx.set_target_weights(weights)
